import '../lib/packet_decoder.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final cold = decodeSensorFrame([0xda, 0xfd, 0x01]);
  check(cold.rawTemperature == -550, 'decoder preserves signed reading');
  check(temperatureCelsius(const SensorFrame(-550, 1)) == -5.5, 'domain converts negative reading');
  check(temperatureCelsius(const SensorFrame(-32768, 1)) == null, 'domain preserves missing sample');
}
